import React, { useState, useEffect } from 'react';
import './DashboardPage.css';
import { timelogAPI, projectAPI } from '../utils/api';

function TimeLogPage() {
  const [timelogs, setTimelogs] = useState([]);
  const [projects, setProjects] = useState([]);
  const [showForm, setShowForm] = useState(false);
  const [loading, setLoading] = useState(true);
  const [formData, setFormData] = useState({
    project_id: '',
    start_time: '',
    end_time: '',
    description: ''
  });

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      setLoading(true);
      const [timelogs, projects] = await Promise.all([
        timelogAPI.getAll(),
        projectAPI.getAll()
      ]);
      setTimelogs(timelogs.data);
      setProjects(projects.data);
    } catch (error) {
      console.error('Failed to fetch data:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await timelogAPI.create(formData);
      setFormData({
        project_id: '',
        start_time: '',
        end_time: '',
        description: ''
      });
      setShowForm(false);
      fetchData();
    } catch (error) {
      console.error('Failed to create timelog:', error);
    }
  };

  const handleDelete = async (id) => {
    if (window.confirm('Are you sure you want to delete this time log?')) {
      try {
        await timelogAPI.delete(id);
        fetchData();
      } catch (error) {
        console.error('Failed to delete timelog:', error);
      }
    }
  };

  if (loading) return <div className="loading">Loading...</div>;

  return (
    <div className="dashboard">
      <h1>⏱️ Time Tracking</h1>

      <button 
        className="btn-primary" 
        onClick={() => setShowForm(!showForm)}
      >
        {showForm ? 'Cancel' : '+ Log Time'}
      </button>

      {showForm && (
        <div className="card form-card">
          <h2>Log Work Time</h2>
          <form onSubmit={handleSubmit}>
            <div className="form-group">
              <label>Project</label>
              <select 
                name="project_id" 
                value={formData.project_id} 
                onChange={handleInputChange}
                required
              >
                <option value="">Select a project</option>
                {projects.map(p => (
                  <option key={p.id} value={p.id}>{p.name}</option>
                ))}
              </select>
            </div>

            <div className="form-group">
              <label>Start Time</label>
              <input 
                type="datetime-local" 
                name="start_time" 
                value={formData.start_time} 
                onChange={handleInputChange}
                required
              />
            </div>

            <div className="form-group">
              <label>End Time</label>
              <input 
                type="datetime-local" 
                name="end_time" 
                value={formData.end_time} 
                onChange={handleInputChange}
                required
              />
            </div>

            <div className="form-group">
              <label>Description</label>
              <textarea 
                name="description" 
                value={formData.description} 
                onChange={handleInputChange}
                placeholder="What did you work on?"
                rows="3"
              />
            </div>

            <button type="submit" className="btn-primary">Log Time</button>
          </form>
        </div>
      )}

      <div className="card">
        <h2>Time Logs</h2>
        {timelogs.length === 0 ? (
          <p>No time logs yet. Start tracking your work!</p>
        ) : (
          <table className="data-table">
            <thead>
              <tr>
                <th>Project</th>
                <th>Hours</th>
                <th>Description</th>
                <th>Date</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {timelogs.map(log => (
                <tr key={log.id}>
                  <td>{projects.find(p => p.id === log.project_id)?.name || 'Unknown'}</td>
                  <td>{log.hours.toFixed(2)}h</td>
                  <td>{log.description}</td>
                  <td>{new Date(log.start_time).toLocaleDateString()}</td>
                  <td>
                    <button 
                      className="btn-small btn-delete" 
                      onClick={() => handleDelete(log.id)}
                    >
                      Delete
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
}

export default TimeLogPage;
